"""Пути файловой системы проекта (поддержка dev и PyInstaller-bundle)."""from __future__ import annotationsimport sysfrom pathlib import Pathdef _is_frozen() -> bool:    return bool(getattr(sys, "frozen", False))def _project_root() -> Path:    if _is_frozen():        return Path(sys.executable).resolve().parent    return Path(__file__).resolve().parents[2]def _resources_root() -> Path:    if _is_frozen():        base = getattr(sys, "_MEIPASS", None)        if base:            return Path(base) / "resources"        return _project_root() / "resources"    return _project_root() / "resources"PROJECT_ROOT: Path = _project_root()EXPORTS_DIR: Path = PROJECT_ROOT / "exports"LOGS_DIR: Path = PROJECT_ROOT / "logs"USER_PLUGINS_DIR: Path = PROJECT_ROOT / "user_plugins"USER_SIGNALS_DIR: Path = USER_PLUGINS_DIR / "signals"USER_FILTERS_DIR: Path = USER_PLUGINS_DIR / "filters"RESOURCES_DIR: Path = _resources_root()HELP_DIR: Path = RESOURCES_DIR / "help"USER_MANUAL_HTML: Path = HELP_DIR / "user_manual.html"def ensure_runtime_dirs() -> None:    for d in (EXPORTS_DIR, LOGS_DIR,              USER_PLUGINS_DIR, USER_SIGNALS_DIR, USER_FILTERS_DIR):        try:            d.mkdir(parents=True, exist_ok=True)        except OSError:            passdef is_frozen() -> bool:    return _is_frozen()